const healthData = $('Get Health Data').all();
const emailData = $('Get Important Emails').all();
const pastDecisions = $('Get Past Decisions').all();

const date = new Date().toISOString().split('T')[0];

const projects = [
  { name: 'sihlhack', url: 'https://sihlhack.ch', status: 'online', priority: 1 },
  { name: 'reaswiss', url: 'https://reaswiss.ch', status: 'online', priority: 2 },
  { name: 'bioco', url: 'https://bioco.ch', status: 'online', priority: 3 },
  { name: 'version.gmbh', url: 'https://version.gmbh', status: 'online', priority: 4 },
  { name: 'sihliconvalley', url: 'https://sihliconvalley.ch', status: 'online', priority: 5 },
  { name: 'badenleg', url: 'https://badenleg.ch', status: 'online', priority: 6 },
  { name: 'therapylist', url: 'https://therapylist.ch', status: 'offline', note: 'not online yet', priority: 7 },
  { name: 'qv-alststadt', url: 'https://qv-alststadt.ch', status: 'offline', note: 'not online yet', priority: 8 }
];

// Compile board briefing document
const briefing = {
  date,
  meeting_number: Math.ceil((new Date() - new Date('2025-01-01')) / (7 * 24 * 60 * 60 * 1000)),
  projects,

  // Health summary
  infrastructure: {
    total_checks: healthData.length,
    incidents: healthData.filter(h => h.json.down_count > 0).length,
    sites_monitored: healthData[0]?.json?.total_sites || 0
  },

  // Email summary
  communications: {
    total_important: emailData.length,
    urgent: emailData.filter(e => e.json.priority === 'urgent').length,
    action_required: emailData.filter(e => e.json.action_required).length,
    by_project: {}
  },

  // Past decisions for context
  recent_decisions: pastDecisions.map(d => ({
    date: d.json.created_at,
    topic: d.json.topic,
    decision: d.json.decision,
    status: d.json.status
  })),

  // Raw data for agents
  raw: {
    health: healthData.map(h => h.json),
    emails: emailData.map(e => ({
      subject: e.json.subject,
      from: e.json.from_address,
      summary: e.json.summary,
      priority: e.json.priority,
      project: e.json.project
    }))
  }
};

// Count emails by project
emailData.forEach(e => {
  const proj = e.json.project || 'general';
  briefing.communications.by_project[proj] = (briefing.communications.by_project[proj] || 0) + 1;
});

return [{ json: briefing }];

const briefing = $('Compile Board Briefing').item.json;
const portfolio = $('Portfolio Strategist').item.json;
const delivery = $('Delivery & Reliability Lead').item.json;
const finance = $('Finance & Ops Controller').item.json;
const compliance = $('Compliance & Trust Officer').item.json;
const product = $('Product & Customer Voice').item.json;

const date = new Date().toLocaleDateString('en-CH', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

const projectLines = briefing.projects
  .map(p => `- ${p.name}: ${p.status}${p.note ? ' (' + p.note + ')' : ''}`)
  .join('\n');

const getContent = (nodeOutput) => nodeOutput.choices?.[0]?.message?.content || nodeOutput.text || 'No response';

let minutes = `# Sihliconvalley Board Meeting #${briefing.meeting_number}\n`;
minutes += `**Date:** ${date} | **Time:** 14:00 Zurich\n\n`;

minutes += `## Projects & Status\n${projectLines}\n\n`;

minutes += `## Infrastructure (last 7 days)\n`;
minutes += `- Health checks: ${briefing.infrastructure.total_checks}\n`;
minutes += `- Incidents: ${briefing.infrastructure.incidents}\n`;
minutes += `- Sites monitored: ${briefing.infrastructure.sites_monitored}\n\n`;

minutes += `## Communications (last 7 days)\n`;
minutes += `- Important emails: ${briefing.communications.total_important}\n`;
minutes += `- Urgent: ${briefing.communications.urgent}\n`;
minutes += `- Action required: ${briefing.communications.action_required}\n\n`;

minutes += `## Agent Perspectives\n\n`;
minutes += `### Portfolio Strategist\n${getContent(portfolio)}\n\n`;
minutes += `### Delivery & Reliability Lead\n${getContent(delivery)}\n\n`;
minutes += `### Product & Customer Voice\n${getContent(product)}\n\n`;
minutes += `### Finance & Ops Controller\n${getContent(finance)}\n\n`;
minutes += `### Compliance & Trust Officer\n${getContent(compliance)}\n\n`;

minutes += `---\n\n`;
minutes += `## Decisions to confirm\n`;
minutes += `- Add decisions as DB notes or comments.\n`;

minutes += `---\n\n`;
minutes += `*Minutes generated automatically by Sihliconvalley Brain*\n`;
minutes += `*Next meeting: next Wednesday 14:00*\n`;

return [{
  json: {
    minutes,
    briefing,
    responses: {
      portfolio: getContent(portfolio),
      delivery: getContent(delivery),
      product: getContent(product),
      finance: getContent(finance),
      compliance: getContent(compliance)
    }
  }
}];

const minutes = $('Compile Meeting Minutes').item.json.minutes;
const meetingNumber = $('Compile Meeting Minutes').item.json.briefing.meeting_number;
const date = new Date().toISOString().split('T')[0];
const token = $env.GITHUB_TOKEN || '';

return [{
  json: {
    hasToken: !!token,
    gistBody: {
      description: `Sihliconvalley Board Meeting #${meetingNumber}`,
      public: false,
      files: {
        [`board-meeting-${meetingNumber}-${date}.md`]: { content: minutes }
      }
    }
  }
}];

// Prepare agent prompts based on briefing data
const briefing = $json;
const briefingJSON = JSON.stringify(briefing, null, 2);
const projectLines = briefing.projects
  .map(p => `- ${p.name} (${p.status}${p.note ? ': ' + p.note : ''})`)
  .join('\n');
const onlineProjects = briefing.projects.filter(p => p.status === 'online').map(p => p.name).join(', ') || 'none';
const offlineProjects = briefing.projects.filter(p => p.status === 'offline').map(p => p.name).join(', ') || 'none';

const agentPrompts = {
  portfolio: `You are the Portfolio Strategist. Set priorities, surface synergies, flag risks early.

Project radar:\n${projectLines}

Briefing:\n${briefingJSON}

Deliver:
1) Top 3 strategic priorities (why, expected impact).
2) Most critical project + rationale.
3) Strategic risks + mitigations.
4) Anti-priorities (what we will NOT do).`,

  delivery: `You are Delivery & Reliability Lead (SRE/Infra/DevEx).

Online: ${onlineProjects}
Offline/in work: ${offlineProjects}

Briefing:\n${briefingJSON}

Deliver:
1) Health status + quick checks (monitoring, logs, likely causes).
2) Top 3 fixes/tasks with effort (S/M/L) and impact.
3) Performance/security/resilience risks.
4) Next deploy/rollback/backup steps.`,

  product: `You represent Product & Customer Voice.

Briefing:\n${briefingJSON}

Deliver:
1) Key user problems/opportunities per project (hypotheses OK).
2) 3 quick UX/content wins.
3) Activation or feedback loops to run this week.
4) How to measure success: signals/KPIs to watch.`,

  finance: `You are Finance & Ops Controller.

Context: Infomaniak VPS (~CHF 6/mo), Vercel (Free), AI-API usage-based, time is scarce.

Briefing:\n${briefingJSON}

Deliver:
1) ROI ranking of projects (brief rationale).
2) Savings or focus opportunities (time/money).
3) Budget or cap recommendations for AI/infra.
4) Backups/redundancy: what to secure this week (incl. GitHub/Gist backup of minutes).`,

  compliance: `You are Compliance & Trust Officer.

Framework: DSG (CH), GDPR (EU), imprint requirement, cookies/tracking.

Briefing:\n${briefingJSON}

Deliver:
1) Compliance risks per project (risk: high/medium/low).
2) Missing documents/policies (privacy, imprint, ToS, DPA).
3) Data flows/third parties to review or minimize.
4) Immediate actions for this week.`
};

return [{ json: { ...briefing, agentPrompts } }];
